  TextField,
  Chip,
  Avatar,
  Tooltip,
} from '@mui/material';
import {
  Videocam as VideocamIcon,
  VideocamOff as VideocamOffIcon,
  Mic as MicIcon,
  MicOff as MicOffIcon,
  ScreenShare as ScreenShareIcon,
  StopScreenShare as StopScreenShareIcon,
  Chat as ChatIcon,
  Close as CloseIcon,
  Send as SendIcon,
  Timer as TimerIcon,
  Help as HelpIcon,
} from '@mui/icons-material';
import axios from 'axios';

interface InterviewDetails {
  id: string;
  jobTitle: string;
  company: string;
  interviewer: {
    name: string;
    role: string;
    avatar?: string;
  };
  duration: number;
  status: 'scheduled' | 'in-progress' | 'completed';
  startTime: string;
  endTime: string;
  questions: Array<{
    id: string;
    text: string;
    type: 'technical' | 'behavioral' | 'situational';
    timeLimit: number;
  }>;
}

interface Message {
  id: string;
  sender: 'interviewer' | 'candidate';
  text: string;
  timestamp: string;
}

const InterviewRoom: React.FC = () => {
  const { interviewId } = useParams<{ interviewId: string }>();
  const navigate = useNavigate();
  const [interview, setInterview] = useState<InterviewDetails | null>(null);
  const [loading, setLoading] = useState(true);
  const [error, setError] = useState<string | null>(null);
  const [videoEnabled, setVideoEnabled] = useState(true);
  const [audioEnabled, setAudioEnabled] = useState(true);
  const [screenSharing, setScreenSharing] = useState(false);
  const [messages, setMessages] = useState<Message[]>([]);
  const [newMessage, setNewMessage] = useState('');
  const [showHelp, setShowHelp] = useState(false);
  const [timeRemaining, setTimeRemaining] = useState<number>(0);
  const [currentQuestionIndex, setCurrentQuestionIndex] = useState(0);
  const [recordingStatus, setRecordingStatus] = useState<'idle' | 'recording' | 'paused'>('idle');

  const videoRef = useRef<HTMLVideoElement>(null);
  const localStreamRef = useRef<MediaStream | null>(null);
  const peerConnectionRef = useRef<RTCPeerConnection | null>(null);
  const messagesEndRef = useRef<HTMLDivElement>(null);

  useEffect(() => {
    const fetchInterviewDetails = async () => {
      try {
        const response = await axios.get(`/api/interviews/${interviewId}`);
        setInterview(response.data);
        setTimeRemaining(response.data.questions[0]?.timeLimit || 0);
      } catch (err) {
        setError('Failed to load interview details');
      } finally {
        setLoading(false);
      }
    };

    fetchInterviewDetails();
  }, [interviewId]);

  useEffect(() => {
    if (timeRemaining > 0) {
      const timer = setInterval(() => {
        setTimeRemaining((prev) => prev - 1);
      }, 1000);
      return () => clearInterval(timer);
    }
  }, [timeRemaining]);

  useEffect(() => {
    messagesEndRef.current?.scrollIntoView({ behavior: 'smooth' });
  }, [messages]);

  const startInterview = async () => {
    try {
      const stream = await navigator.mediaDevices.getUserMedia({
        video: true,
        audio: true,
      });
      localStreamRef.current = stream;
      if (videoRef.current) {
        videoRef.current.srcObject = stream;
      }

      // Initialize WebRTC connection
      const peerConnection = new RTCPeerConnection({
        iceServers: [{ urls: 'stun:stun.l.google.com:19302' }],
      });

      stream.getTracks().forEach((track) => {
        peerConnection.addTrack(track, stream);
      });

      peerConnectionRef.current = peerConnection;

      // Handle incoming tracks
      peerConnection.ontrack = (event) => {
        if (videoRef.current) {
          videoRef.current.srcObject = event.streams[0];
        }
      };

      // Create and send offer
      const offer = await peerConnection.createOffer();
      await peerConnection.setLocalDescription(offer);

      // Send offer to server
      await axios.post(`/api/interviews/${interviewId}/offer`, {
        offer: peerConnection.localDescription,
      });

      setRecordingStatus('recording');
    } catch (err) {
      setError('Failed to start video interview');
    }
  };

  const toggleVideo = () => {
    if (localStreamRef.current) {
      const videoTrack = localStreamRef.current.getVideoTracks()[0];
      videoTrack.enabled = !videoTrack.enabled;
      setVideoEnabled(videoTrack.enabled);
    }
  };

  const toggleAudio = () => {
    if (localStreamRef.current) {
      const audioTrack = localStreamRef.current.getAudioTracks()[0];
      audioTrack.enabled = !audioTrack.enabled;
      setAudioEnabled(audioTrack.enabled);
    }
  };

  const toggleScreenShare = async () => {
    try {
      if (!screenSharing) {
        const stream = await navigator.mediaDevices.getDisplayMedia({
          video: true,
        });
        const videoTrack = stream.getVideoTracks()[0];
        if (peerConnectionRef.current) {
          const sender = peerConnectionRef.current
            .getSenders()
            .find((s) => s.track?.kind === 'video');
          if (sender) {
            sender.replaceTrack(videoTrack);
          }
        }
        setScreenSharing(true);
      } else {
        if (localStreamRef.current) {
          const videoTrack = localStreamRef.current.getVideoTracks()[0];
          if (peerConnectionRef.current) {
            const sender = peerConnectionRef.current
              .getSenders()
              .find((s) => s.track?.kind === 'video');
            if (sender) {
              sender.replaceTrack(videoTrack);
            }
          }
        }
        setScreenSharing(false);
      }
    } catch (err) {
      setError('Failed to toggle screen sharing');
    }
  };

  const sendMessage = () => {
    if (newMessage.trim()) {
      const message: Message = {
        id: Date.now().toString(),
        sender: 'candidate',
        text: newMessage,
        timestamp: new Date().toISOString(),
      };
      setMessages((prev) => [...prev, message]);
      setNewMessage('');
    }
  };

  const formatTime = (seconds: number) => {
    const minutes = Math.floor(seconds / 60);
    const remainingSeconds = seconds % 60;
    return `${minutes}:${remainingSeconds.toString().padStart(2, '0')}`;
  };

  const handleNextQuestion = () => {
    if (interview && currentQuestionIndex < interview.questions.length - 1) {
      setCurrentQuestionIndex((prev) => prev + 1);
      setTimeRemaining(interview.questions[currentQuestionIndex + 1].timeLimit);
    }
  };

  const endInterview = async () => {
    try {
      if (peerConnectionRef.current) {
        peerConnectionRef.current.close();
      }
      if (localStreamRef.current) {
        localStreamRef.current.getTracks().forEach((track) => track.stop());
      }
      await axios.post(`/api/interviews/${interviewId}/end`);
      navigate('/dashboard');
    } catch (err) {
      setError('Failed to end interview');
    }
  };

  if (loading) {
    return (
      <Box display="flex" justifyContent="center" alignItems="center" minHeight="80vh">
        <CircularProgress />
      </Box>
    );
  }

  if (error || !interview) {
    return (
      <Container maxWidth="md" sx={{ py: 4 }}>
        <Alert severity="error">{error || 'Interview not found'}</Alert>
      </Container>
    );
  }

  return (
    <Container maxWidth="lg" sx={{ py: 4 }}>
      <Grid container spacing={3}>
        <Grid item xs={12} md={8}>
          <Paper elevation={3} sx={{ p: 2, mb: 2 }}>
            <Box display="flex" justifyContent="space-between" alignItems="center" mb={2}>
              <Typography variant="h5">
                {interview.jobTitle} Interview
              </Typography>
              <Box display="flex" alignItems="center" gap={1}>
                <TimerIcon />
                <Typography variant="body1">
                  {formatTime(timeRemaining)}
                </Typography>
              </Box>
            </Box>

            <Box
              sx={{
                position: 'relative',
                width: '100%',
                paddingTop: '56.25%', // 16:9 aspect ratio
                backgroundColor: 'grey.900',
                borderRadius: 1,
                overflow: 'hidden',
              }}
            >
              <video
                ref={videoRef}
                autoPlay
                playsInline
                style={{
                  position: 'absolute',
                  top: 0,
                  left: 0,
                  width: '100%',
                  height: '100%',
                  objectFit: 'cover',
                }}
              />
            </Box>

            <Box display="flex" justifyContent="center" gap={2} mt={2}>
              <Tooltip title={videoEnabled ? 'Turn off camera' : 'Turn on camera'}>
                <IconButton
                  onClick={toggleVideo}
                  color={videoEnabled ? 'primary' : 'error'}
                >
                  {videoEnabled ? <VideocamIcon /> : <VideocamOffIcon />}
                </IconButton>
              </Tooltip>
              <Tooltip title={audioEnabled ? 'Mute microphone' : 'Unmute microphone'}>
                <IconButton
                  onClick={toggleAudio}
                  color={audioEnabled ? 'primary' : 'error'}
                >
                  {audioEnabled ? <MicIcon /> : <MicOffIcon />}
                </IconButton>
              </Tooltip>
              <Tooltip title={screenSharing ? 'Stop sharing' : 'Share screen'}>
                <IconButton
                  onClick={toggleScreenShare}
                  color={screenSharing ? 'primary' : 'default'}
                >
                  {screenSharing ? <StopScreenShareIcon /> : <ScreenShareIcon />}
                </IconButton>
              </Tooltip>
              <Tooltip title="Help">
                <IconButton onClick={() => setShowHelp(true)}>
                  <HelpIcon />
                </IconButton>
              </Tooltip>
            </Box>
          </Paper>

          <Paper elevation={3} sx={{ p: 2 }}>
            <Typography variant="h6" gutterBottom>
              Current Question
            </Typography>
            {interview.questions[currentQuestionIndex] && (
              <Box>
                <Typography variant="body1" paragraph>
                  {interview.questions[currentQuestionIndex].text}
                </Typography>
                <Chip
                  label={interview.questions[currentQuestionIndex].type}
                  color="primary"
                  size="small"
                />
              </Box>
            )}
            <Box display="flex" justifyContent="flex-end" mt={2}>
              <Button
                variant="contained"
                onClick={handleNextQuestion}
                disabled={currentQuestionIndex >= interview.questions.length - 1}
              >
                Next Question
              </Button>
            </Box>
          </Paper>
        </Grid>

        <Grid item xs={12} md={4}>
          <Paper elevation={3} sx={{ p: 2, height: '100%' }}>
            <Box display="flex" alignItems="center" mb={2}>
              <Avatar
                src={interview.interviewer.avatar}
                sx={{ width: 40, height: 40, mr: 1 }}
              >
                {interview.interviewer.name.charAt(0)}
              </Avatar>
              <Box>
                <Typography variant="subtitle1">
                  {interview.interviewer.name}
                </Typography>
                <Typography variant="body2" color="text.secondary">
                  {interview.interviewer.role}
                </Typography>
              </Box>
            </Box>

            <Box
              sx={{
                height: 'calc(100% - 100px)',
                overflowY: 'auto',
                mb: 2,
              }}
            >
              {messages.map((message) => (
                <Box
                  key={message.id}
                  sx={{
                    display: 'flex',
                    justifyContent: message.sender === 'candidate' ? 'flex-end' : 'flex-start',
                    mb: 1,
                  }}
                >
                  <Paper
                    sx={{
                      p: 1,
                      maxWidth: '70%',
                      backgroundColor: message.sender === 'candidate' ? 'primary.main' : 'grey.100',
                      color: message.sender === 'candidate' ? 'white' : 'text.primary',
                    }}
                  >
                    <Typography variant="body2">{message.text}</Typography>
                    <Typography variant="caption" sx={{ opacity: 0.7 }}>
                      {new Date(message.timestamp).toLocaleTimeString()}
                    </Typography>
                  </Paper>
                </Box>
              ))}
              <div ref={messagesEndRef} />
            </Box>

            <Box display="flex" gap={1}>
              <TextField
                fullWidth
                size="small"
                placeholder="Type a message..."
                value={newMessage}
                onChange={(e) => setNewMessage(e.target.value)}
                onKeyPress={(e) => {
                  if (e.key === 'Enter') {
                    sendMessage();
                  }
                }}
              />
              <IconButton onClick={sendMessage} color="primary">
                <SendIcon />
              </IconButton>
            </Box>
          </Paper>
        </Grid>
      </Grid>

      <Dialog open={showHelp} onClose={() => setShowHelp(false)}>
        <DialogTitle>Interview Help</DialogTitle>
        <DialogContent>
          <Typography variant="body1" paragraph>
            Welcome to your interview! Here are some tips:
          </Typography>
          <Typography variant="body2" component="div">
            <ul>
              <li>Make sure you have a stable internet connection</li>
              <li>Test your camera and microphone before starting</li>
              <li>Find a quiet, well-lit environment</li>
              <li>Dress professionally</li>
              <li>Have your resume and notes ready</li>
              <li>Use the chat feature for any technical issues</li>
            </ul>
          </Typography>
        </DialogContent>
        <DialogActions>
          <Button onClick={() => setShowHelp(false)}>Close</Button>
        </DialogActions>
      </Dialog>
    </Container>
  );
};

export default InterviewRoom;
